var e={solar_flare:{id:`solar_flare`,name:`Solar Flare`,description:`A coronal mass ejection has damaged collector arrays. Pay repair materials, then allow 30 seconds for crews to re-seat and test each panel before construction can resume.`,resolutionCost:{steel:300,electronics:100},progressPenalty:.2,pauseWindowTicks:1800},alien_interference:{id:`alien_interference`,name:`Alien Interference`,description:`[ARIA] Unidentified probe signatures detected near the construction lattice. Deploy electronic countermeasures, then hold position for 60 seconds while we confirm the interference pattern has cleared — or sacrifice 30% of stage progress to route around the disruption.`,resolutionCost:{electronics:200},progressPenalty:.3,pauseWindowTicks:3600},structural_failure:{id:`structural_failure`,name:`Structural Failure`,description:`A primary truss segment buckled under thermal stress. Emergency steel reinforcement required, followed by a mandatory 90-second structural re-inspection before construction loads can be reapplied.`,resolutionCost:{steel:1500},progressPenalty:.35,pauseWindowTicks:5400},spin_bearing_failure:{id:`spin_bearing_failure`,name:`Spin Bearing Failure`,description:`A primary bearing in the habitat spin ring has seized. Deploy refined nickel and steel for emergency replacement, then hold for 40 seconds of re-balancing calibration.`,resolutionCost:{refined_nickel:500,steel:800},progressPenalty:.2,pauseWindowTicks:2400},atmosphere_breach:{id:`atmosphere_breach`,name:`Atmosphere Breach`,description:`A micro-meteorite has punctured the habitat hull. Seal with steel plating and carbon fiber composite, then allow 60 seconds for atmosphere re-pressurization.`,resolutionCost:{steel:1e3,carbon_fiber:600},progressPenalty:.3,pauseWindowTicks:3600},mirror_contamination:{id:`mirror_contamination`,name:`Mirror Contamination`,description:`Micro-debris has contaminated 30% of collector arrays. Fabricate replacement silicon panels, then wait 40 seconds for alignment calibration to complete — or lose 25% of stage progress.`,resolutionCost:{silicon_wafer:400},progressPenalty:.25,pauseWindowTicks:2400}},t={orbital_platform:{id:`orbital_platform`,name:`Orbital Platform`,description:`A massive rotating ring structure above the asteroid belt. Serves as a super-base visible from max zoom.`,stages:[{index:0,name:`Scaffold`,description:`Basic structural framework. Orbital sensor array routes targeting data to robots.`,cost:{refined_iron:5e3,silicon_wafer:2e3},engineersRequired:1,baseTicks:54e3,bonus:{type:`robot_cap`,value:3,description:`+3 robot cap (orbital sensor array)`}},{index:1,name:`Core`,description:`Central command and life support modules. Increases robot cap by 20.`,cost:{refined_iron:15e3,carbon_fiber:8e3},engineersRequired:2,baseTicks:108e3,bonus:{type:`robot_cap`,value:20,description:`+20 robot cap`}},{index:2,name:`Complete`,description:`Fully operational mega-base. The orbital depot expands your operational capacity.`,cost:{refined_iron:3e4,silicon_wafer:8e3,carbon_fiber:8e3},engineersRequired:3,baseTicks:216e3,bonus:{type:`robot_cap`,value:10,description:`+10 robot cap (orbital depot)`}}]},human_habitat:{id:`human_habitat`,name:`Human Habitat`,description:`A rotating habitat module capable of sustaining human colonists. Three construction stages: radiation shielding, spin gravity, and life support.`,stageTechGates:{0:[`habitat_module`],1:[`fission_reactor`],2:[`automated_logistics`]},stages:[{index:0,name:`Radiation Shell`,description:`Five meters of regolith-equivalent shielding to protect against cosmic radiation. A shielded workspace for robots as a bonus.`,cost:{steel:2e4,refined_iron:1e4,carbon_fiber:5e3},engineersRequired:2,baseTicks:108e3,bonus:{type:`robot_cap`,value:5,description:`+5 robot cap (shielded workspace)`},crisisType:`structural_failure`},{index:1,name:`Spin Ring`,description:`A 225-meter radius rotating structure providing 0.38g artificial gravity. Structural maintenance consumes steel and electronics.`,cost:{steel:4e4,electronics:15e3,carbon_fiber:1e4,refined_nickel:5e3},engineersRequired:3,baseTicks:216e3,bonus:{type:`robot_cap`,value:5,description:`+5 robot cap (centrifuge cargo bays)`},activeDrain:{steel:5,electronics:3},drainIntervalTicks:3600,crisisType:`spin_bearing_failure`},{index:2,name:`Life Support`,description:`Water recycling, CO₂ scrubbing, and oxygen generation systems. Continuous life support drain begins. Completion triggers human arrival.`,cost:{steel:6e4,electronics:3e4,water:2e4,oxygen:1e4,carbon_fiber:15e3},engineersRequired:4,baseTicks:324e3,bonus:{type:`habitat_ready`,value:1,description:`Humans can now arrive — narrative trigger: humans_arrive`},activeDrain:{water:10,oxygen:5,electronics:4},drainIntervalTicks:3600,crisisType:`atmosphere_breach`}]},dyson_swarm:{id:`dyson_swarm`,name:`Dyson Swarm`,description:`A growing constellation of energy collectors surrounding the local star. The ultimate endgame goal — but the path there will stress every part of your operation.`,prerequisite:{id:`orbital_platform`,minCompletedStages:3},stageTechGates:{3:[`anomaly_scanning`],5:[`signal_analysis`],7:[`spatial_distortion_study`]},stages:[{index:0,name:`First Collectors`,description:`Initial mirror array launched into stellar orbit.`,cost:{steel:15e3,electronics:8e3},engineersRequired:2,baseTicks:108e3,bonus:{type:`energy_unlimited`,value:1,description:`Unlimited energy for nearby robots`}},{index:1,name:`Solar Alignment`,description:`Precision alignment of collector arrays to maximise stellar flux. The calibration process continuously burns through batteries.`,cost:{steel:3e4,electronics:15e3,battery_cell:1e4},engineersRequired:2,baseTicks:18e4,bonus:{type:`sensor_range`,value:2,description:`2× sensor range`},activeDrain:{battery_cell:8},drainIntervalTicks:3600},{index:2,name:`Relay Network`,description:`Wide-band energy relay grid bridging collectors across the inner system.`,cost:{steel:5e4,electronics:25e3,battery_cell:2e4},engineersRequired:3,baseTicks:216e3,bonus:{type:`robot_cap`,value:3,description:`+3 robot cap (relay network coordination)`},crisisType:`solar_flare`},{index:3,name:`Resonance Chamber`,description:`[ARIA] Warning: Stage 4 requires sustained harmonic resonance. Your refinery will need to run battery and carbon-fiber production in parallel — non-stop — for the duration of construction. Anomaly scanning research is required to calibrate harmonic frequencies.`,cost:{steel:8e4,electronics:4e4,battery_cell:35e3,carbon_fiber:2e4},engineersRequired:3,baseTicks:324e3,bonus:{type:`robot_cap`,value:25,description:`+25 robot cap`},activeDrain:{battery_cell:15,carbon_fiber:8},drainIntervalTicks:3600},{index:4,name:`Primary Focus Array`,description:`The central focusing array that channels stellar output toward your operation. ARIA has flagged anomalous probe signatures in this sector.`,cost:{steel:12e4,electronics:6e4,battery_cell:5e4},engineersRequired:4,baseTicks:432e3,bonus:{type:`sensor_range`,value:3,description:`3× sensor range (stacks)`},crisisType:`alien_interference`},{index:5,name:`Secondary Lattice`,description:`[ARIA] The secondary lattice requires continuous electronic upkeep. Your platinum-to-electronics pipeline must run uninterrupted. Signal analysis research reveals the structural resonance patterns needed for lattice stability.`,cost:{steel:18e4,electronics:1e5,battery_cell:8e4,refined_nickel:4e4},engineersRequired:4,baseTicks:54e4,bonus:{type:`energy_unlimited`,value:2,description:`Energy unlimited (enhanced)`},activeDrain:{electronics:12},drainIntervalTicks:3600},{index:6,name:`Outer Shell`,description:`The outer collector shell spans the full stellar orbit. Thermal cycling at this scale makes structural failures likely.`,cost:{steel:3e5,electronics:15e4,battery_cell:12e4,refined_nickel:6e4,carbon_fiber:5e4},engineersRequired:5,baseTicks:648e3,bonus:{type:`robot_cap`,value:50,description:`+50 robot cap`},activeDrain:{battery_cell:25},drainIntervalTicks:3600,crisisType:`structural_failure`},{index:7,name:`Dyson Sphere`,description:`The swarm reaches full enclosure. [ARIA] I want you to know: the energy signature we're about to produce will be detectable as a Type II civilization from 847 light-years away. We are no longer hiding. If anything out there was waiting for a reason to notice us — we are about to give it one.`,cost:{steel:5e5,electronics:25e4,battery_cell:2e5,refined_nickel:1e5,carbon_fiber:8e4},engineersRequired:5,baseTicks:864e3,bonus:{type:`win_condition`,value:1,description:`You have achieved the ultimate goal.`},activeDrain:{battery_cell:30,electronics:15},drainIntervalTicks:3600,crisisType:`mirror_contamination`}]},relay_network:{id:`relay_network`,name:`Dyson Relay Network`,description:`A deep-space signal amplification array extending the Dyson Sphere's reach across multiple star systems. Post-Dyson endgame megastructure.`,prerequisite:{id:`dyson_swarm`,minCompletedStages:8},stages:[{index:0,name:`Signal Foundation`,description:`[ARIA] With the Dyson Sphere complete, we can now focus surplus energy into interstellar signal transmission. This relay foundation will amplify our reach beyond the local system.`,cost:{steel:5e4,electronics:25e3,silicon_wafer:15e3},engineersRequired:3,baseTicks:108e3,bonus:{type:`sensor_range`,value:5,description:`5× sensor range (relay amplification)`}},{index:1,name:`Amplifier Array`,description:`Precision-tuned amplifier nodes that boost signal coherence across light-years. Requires continuous battery and electronics upkeep.`,cost:{steel:1e5,electronics:5e4,battery_cell:4e4,carbon_fiber:2e4},engineersRequired:3,baseTicks:216e3,bonus:{type:`robot_cap`,value:15,description:`+15 robot cap (relay coordination network)`},activeDrain:{battery_cell:10,electronics:5},drainIntervalTicks:3600},{index:2,name:`Resonance Bridge`,description:`[ARIA] The bridge is channeling energy patterns I have never observed. The signal harmonics suggest something is... responding. I recommend caution — and curiosity.`,cost:{steel:2e5,electronics:1e5,battery_cell:8e4,refined_nickel:4e4},engineersRequired:4,baseTicks:324e3,bonus:{type:`energy_unlimited`,value:3,description:`Energy unlimited (relay network)`},activeDrain:{battery_cell:20,electronics:10},drainIntervalTicks:3600,crisisType:`alien_interference`},{index:3,name:`Relay Complete`,description:`[ARIA] The Dyson Relay Network is operational. Our signal now reaches across 12 star systems. Whatever is out there — we have announced ourselves not with a whisper, but with a lighthouse. The fleet's culture resonates through the relay. This is their legacy.`,cost:{steel:35e4,electronics:175e3,battery_cell:12e4,refined_nickel:6e4,carbon_fiber:5e4},engineersRequired:5,baseTicks:432e3,bonus:{type:`robot_cap`,value:30,description:`+30 robot cap — Relay Complete`},activeDrain:{battery_cell:25,electronics:12},drainIntervalTicks:3600,crisisType:`mirror_contamination`}]}};export{t as n,e as t};
